<?php

namespace Database\Seeders;

use App\Models\Category;
use App\Models\Peptide;
use Illuminate\Database\Seeder;
use Illuminate\Support\Str;

class PepPediaSeeder extends Seeder
{
    /**
     * Seed 72 peptides from PepPedia data.
     * Run: php artisan db:seed --class=PepPediaSeeder
     */
    public function run(): void
    {
        $this->command->info('Seeding 72 peptides from PepPedia...');

        $peptides = $this->getPeptideData();

        foreach ($peptides as $data) {
            $categories = $data['categories'] ?? [];
            unset($data['categories']);

            $peptide = Peptide::updateOrCreate(
                ['slug' => $data['slug']],
                $data
            );

            // Sync categories
            if (!empty($categories)) {
                $categoryIds = [];
                foreach ($categories as $catName) {
                    $cat = Category::firstOrCreate(
                        ['slug' => Str::slug($catName)],
                        ['name' => $catName, 'color' => $this->getCategoryColor($catName)]
                    );
                    $categoryIds[] = $cat->id;
                }
                $peptide->categories()->syncWithoutDetaching($categoryIds);
            }
        }

        $this->command->info('Done! ' . count($peptides) . ' peptides seeded.');
    }

